const startMTX = async () => {
    const status = document.getElementById('engine-status');
    const log = document.getElementById('exec-log');
    const gfVal = document.getElementById('gflops-val');
    const timeVal = document.getElementById('time-val');

    if (!navigator.gpu) { status.innerText = "[ ERROR: WEBGPU_NOT_FOUND ]"; return; }

    const adapter = await navigator.gpu.requestAdapter();
    const device = await adapter.requestDevice();
    status.innerText = "[ HARDWARE_ACTIVE: RADEON_PRO_575X ]";

    const SIZE = 4096;
    const BLOCK_SIZE = 32;
    const TILE_SIZE = 4; // 4x4 Register Tiling per thread

    // This is the direct port of the MTX Metal Kernel logic to WGSL
    // incorporating the 4x4 Register Tiling ("ZA-Storage") mentioned in the MTX README
    const wgsl = `
        struct P { M: u32, N: u32, K: u32, pad: u32 };

        @group(0) @binding(0) var<storage, read> A: array<f32>;
        @group(0) @binding(1) var<storage, read> B: array<f32>;
        @group(0) @binding(2) var<storage, read_write> C: array<f32>;
        @group(0) @binding(3) var<uniform> p: P;

        var<workgroup> sA: array<f32, ${BLOCK_SIZE * BLOCK_SIZE}>;
        var<workgroup> sB: array<f32, ${BLOCK_SIZE * BLOCK_SIZE}>;

        @compute @workgroup_size(${BLOCK_SIZE / TILE_SIZE}, ${BLOCK_SIZE / TILE_SIZE})
        fn main(
            @builtin(workgroup_id) group_id: vec3<u32>,
            @builtin(local_invocation_id) local_id: vec3<u32>
        ) {
            // MTX 4x4 Register Tiling (ZA-Storage)
            var c_tile: array<f32, 16>; 
            for(var i=0u; i<16u; i++) { c_tile[i] = 0.0; }

            let row_block = group_id.y * ${BLOCK_SIZE}u;
            let col_block = group_id.x * ${BLOCK_SIZE}u;

            let ty = local_id.y * ${TILE_SIZE}u;
            let tx = local_id.x * ${TILE_SIZE}u;

            let K = p.K;

            for (var k_blk = 0u; k_blk < K; k_blk += ${BLOCK_SIZE}u) {

                // Cooperative Global -> Shared (LDS) loading
                for (var r = 0u; r < ${TILE_SIZE}u; r++) {
                    for (var c = 0u; c < ${TILE_SIZE}u; c++) {
                        let l_y = ty + r; let l_x = tx + c;

                        let g_a_row = row_block + l_y;
                        let g_a_col = k_blk + l_x;
                        sA[l_y * ${BLOCK_SIZE}u + l_x] = A[g_a_row * K + g_a_col];

                        let g_b_row = k_blk + l_y;
                        let g_b_col = col_block + l_x;
                        sB[l_y * ${BLOCK_SIZE}u + l_x] = B[g_b_row * p.N + g_b_col];
                    }
                }

                workgroupBarrier();

                // Compute 4x4 Register Tile
                for (var k = 0u; k < ${BLOCK_SIZE}u; k++) {
                    // Pre-load operands into registers
                    var a_reg: array<f32, ${TILE_SIZE}>;
                    var b_reg: array<f32, ${TILE_SIZE}>;

                    for (var i = 0u; i < ${TILE_SIZE}u; i++) {
                        a_reg[i] = sA[(ty + i) * ${BLOCK_SIZE}u + k];
                        b_reg[i] = sB[k * ${BLOCK_SIZE}u + (tx + i)];
                    }

                    // Outer product accumulation
                    for (var r = 0u; r < ${TILE_SIZE}u; r++) {
                        for (var c = 0u; c < ${TILE_SIZE}u; c++) {
                            c_tile[r * ${TILE_SIZE}u + c] += a_reg[r] * b_reg[c];
                        }
                    }
                }

                workgroupBarrier();
            }

            // Write 4x4 tile back to global memory
            for (var r = 0u; r < ${TILE_SIZE}u; r++) {
                for (var c = 0u; c < ${TILE_SIZE}u; c++) {
                    let g_row = row_block + ty + r;
                    let g_col = col_block + tx + c;
                    if (g_row < p.M && g_col < p.N) {
                        C[g_row * p.N + g_col] = c_tile[r * ${TILE_SIZE}u + c];
                    }
                }
            }
        }
    `;

    const module = device.createShaderModule({ code: wgsl });
    const pipeline = device.createComputePipeline({ layout: 'auto', compute: { module, entryPoint: 'main' } });

    const byteSize = SIZE * SIZE * 4;
    const bA = device.createBuffer({ size: byteSize, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
    const bB = device.createBuffer({ size: byteSize, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
    const bC = device.createBuffer({ size: byteSize, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC | GPUBufferUsage.COPY_DST });
    const bP = device.createBuffer({ size: 16, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
    const bRead = device.createBuffer({ size: 4, usage: GPUBufferUsage.MAP_READ | GPUBufferUsage.COPY_DST }); // Just for sync

    device.queue.writeBuffer(bP, 0, new Uint32Array([SIZE, SIZE, SIZE, 0]));

    // Initialize with dummy data (skip JS array creation to avoid RAM bottleneck, just map empty)
    // In a real scenario we'd use the HuggingFace weights here.

    const bindGroup = device.createBindGroup({
        layout: pipeline.getBindGroupLayout(0),
        entries: [
            { binding: 0, resource: { buffer: bA } },
            { binding: 1, resource: { buffer: bB } },
            { binding: 2, resource: { buffer: bC } },
            { binding: 3, resource: { buffer: bP } }
        ]
    });

    window.runMTXBenchmark = async () => {
        log.innerHTML += `\n> TRIGGERING MTX KERNEL...\n> MATRIX: ${SIZE}x${SIZE}\n> LAUNCHING COMMAND BUFFER...`;

        const enc = device.createCommandEncoder();
        const pass = enc.beginComputePass();
        pass.setPipeline(pipeline);
        pass.setBindGroup(0, bindGroup);
        // Dispatch grid dimensions
        const gridDim = Math.ceil(SIZE / BLOCK_SIZE);
        pass.dispatchWorkgroups(gridDim, gridDim);
        pass.end();

        // Copy 1 byte to trigger synchronization
        enc.copyBufferToBuffer(bC, 0, bRead, 0, 4);

        const startT = performance.now();
        device.queue.submit([enc.finish()]);

        await bRead.mapAsync(GPUMapMode.READ);
        const timeMs = performance.now() - startT;
        bRead.unmap();

        const ops = 2.0 * Math.pow(SIZE, 3);
        const gflops = (ops / timeMs) / 1000000.0;

        log.innerHTML += `\n> EXECUTION COMPLETE.\n> LATENCY: ${timeMs.toFixed(2)} ms`;
        gfVal.innerText = gflops.toFixed(1);
        timeVal.innerText = `Latency: ${timeMs.toFixed(2)} ms`;

        window.axiomaticLog({ event: "MTX_Kernel_Executed", gflops, timeMs });
    };

    window.axiomaticLog({ event: "MTX_Studio_Online" });
}; startMTX();
